"""User store."""

class UserStore:
    def __init__(self):
        self.users = {}

    def create_user(self, username, role="viewer"):
        self.users[username] = {"username": username, "role": role}
        return self.users[username]

    def get_user(self, username):
        return self.users.get(username)

