"""Role-based permissions."""

ROLE_PERMISSIONS = {
    "viewer": ["read"],
    "editor": ["read", "write"],
    "admin": ["write", "delete", "manage_users"],
}

def get_permissions(role):
    return ROLE_PERMISSIONS.get(role, [])

def has_permission(role, permission):
    return permission in get_permissions(role)

